// ─── Profile / My Workspace Page ──────────────────────────────────────────
const PROFILE_USER = {
  name: "Jordan Park",
  nameZh: "朴俊浩",
  email: "jordan.park@company.com",
  dept: "eng.cloud.infra",
  bio: "Building internal platform tools. Coffee-driven debugging.",
  bioZh: "构建内部平台工具。咖啡驱动的调试。",
  joined: "Apr 2024",
  avatar: "JP",
};

// Which extensions in the marketplace are "mine" (published by this user)
const MY_PUBLISHED_IDS = [2, 5, 8];
const MY_DRAFTS = [
  { id: "d1", name: "Database Schema Inspector", type: "skill", lastEdited: "2 days ago", lastEditedZh: "2 天前", progress: 0.6 },
];

const RECENT_ACTIVITY = [
  { id:"a1", kind:"installed", extId:1, when:"today", at:"2h ago", atZh:"2 小时前" },
  { id:"a2", kind:"reviewed", extId:5, when:"today", at:"5h ago", atZh:"5 小时前", meta:"★★★★★" },
  { id:"a3", kind:"updated",  extId:3, when:"yesterday", at:"v2.4.1", atZh:"v2.4.1" },
  { id:"a4", kind:"published",extId:8, when:"thisweek", at:"v1.2.0", atZh:"v1.2.0" },
  { id:"a5", kind:"installed",extId:7, when:"thisweek", at:"3d ago", atZh:"3 天前" },
  { id:"a6", kind:"uninstalled",extId:6, when:"earlier", at:"Apr 28", atZh:"4 月 28 日" },
  { id:"a7", kind:"published",extId:5, when:"earlier", at:"Apr 12", atZh:"4 月 12 日" },
];

function ProfilePage({ lang, t, theme, isDark, cardRadius, cardGap, density, section, setSection, settingsTab, setSettingsTab, installed, saved, onClose, onOpenExt, onPublish, onBrowse, onUninstall, toggleSave }) {
  const installedExts = EXTENSIONS.filter(e => installed.has(e.id));
  const publishedExts = EXTENSIONS.filter(e => MY_PUBLISHED_IDS.includes(e.id));
  const savedExts = EXTENSIONS.filter(e => saved.has(e.id));

  const totalInstalls = publishedExts.reduce((s,e)=>s + (e.downloads||0), 0);
  const avgRating = publishedExts.length ? (publishedExts.reduce((s,e)=>s+(e.stars||0),0)/publishedExts.length).toFixed(2) : "—";

  const sections = [
    { key:"installed", label:t.profile_section_installed, icon:"check",   count:installedExts.length },
    { key:"published", label:t.profile_section_published, icon:"upload",  count:publishedExts.length },
    { key:"drafts",    label:t.profile_section_drafts,    icon:"edit",    count:MY_DRAFTS.length },
    { key:"saved",     label:t.profile_section_saved,     icon:"bookmark",count:savedExts.length },
    { key:"activity",  label:t.profile_section_activity,  icon:"clock" },
    { key:"settings",  label:t.profile_section_settings,  icon:"bars" },
  ];

  const userName = lang==="zh" ? PROFILE_USER.nameZh : PROFILE_USER.name;

  return (
    <div style={{ maxWidth:1200, margin:"0 auto", animation:"fadeIn 0.3s ease" }}>
      {/* ── Hero strip ── */}
      <div style={{
        background: isDark ? "#1a1815" : "#faf6ee",
        border: `1px solid ${theme.cardBorder}`,
        borderRadius: cardRadius+4,
        padding: "26px 30px",
        marginBottom: 22,
        display: "flex",
        alignItems: "center",
        gap: 24,
      }}>
        <div style={{
          width:72, height:72, borderRadius:"50%",
          background: theme.accent,
          color:"#fff",
          display:"flex", alignItems:"center", justifyContent:"center",
          fontFamily:"'Source Serif 4','Source Serif Pro',Georgia,serif",
          fontSize:28, fontWeight:600, letterSpacing:"-0.02em",
          flexShrink:0,
          boxShadow:`0 4px 14px ${theme.accent}55`,
        }}>{PROFILE_USER.avatar}</div>

        <div style={{ flex:1, minWidth:0 }}>
          <h1 style={{
            fontFamily:"'Source Serif 4','Source Serif Pro',Georgia,serif",
            fontSize:30, fontWeight:600, color:theme.text,
            margin:"0 0 4px 0", letterSpacing:"-0.02em",
          }}>{userName}</h1>
          <div style={{ fontSize:13, color:theme.textMuted, display:"flex", alignItems:"center", gap:10, flexWrap:"wrap" }}>
            <span>{t.profile_role}</span>
            <span style={{ width:3, height:3, borderRadius:"50%", background:theme.textMuted, opacity:0.5 }}/>
            <span>{t.profile_dept}</span>
            <span style={{ width:3, height:3, borderRadius:"50%", background:theme.textMuted, opacity:0.5 }}/>
            <span>{t.profile_joined}</span>
          </div>
        </div>

        {/* Mini stats */}
        <div style={{ display:"flex", gap:28, alignItems:"center", paddingRight:8 }}>
          <ProfileStat value={installedExts.length} label={t.profile_stat_installed} theme={theme}/>
          <div style={{ width:1, height:36, background:theme.cardBorder }}/>
          <ProfileStat value={publishedExts.length} label={t.profile_stat_published} theme={theme}/>
          <div style={{ width:1, height:36, background:theme.cardBorder }}/>
          <ProfileStat value={totalInstalls.toLocaleString()} label={t.profile_stat_installs} theme={theme}/>
          <div style={{ width:1, height:36, background:theme.cardBorder }}/>
          <ProfileStat value={avgRating} label={t.profile_stat_rating} theme={theme} suffix={publishedExts.length ? "★" : ""}/>
        </div>
      </div>

      {/* ── Two-column body ── */}
      <div style={{ display:"flex", gap:28, alignItems:"flex-start" }}>
        {/* Section rail */}
        <div style={{ width:200, flexShrink:0, position:"sticky", top:0 }}>
          <div style={{ display:"flex", flexDirection:"column", gap:2 }}>
            {sections.map(s => {
              const active = section === s.key;
              return (
                <button key={s.key} onClick={() => setSection(s.key)}
                  style={{
                    display:"flex", alignItems:"center", gap:10,
                    padding:"9px 12px", borderRadius:8,
                    background: active ? `${theme.accent}14` : "transparent",
                    border:"none", cursor:"pointer",
                    color: active ? theme.text : theme.textMuted,
                    fontSize:13.5, fontWeight: active ? 600 : 500,
                    textAlign:"left",
                    transition:"background 0.12s",
                    fontFamily:"inherit",
                  }}
                  onMouseEnter={e => { if (!active) e.currentTarget.style.background = theme.filterBg; }}
                  onMouseLeave={e => { if (!active) e.currentTarget.style.background = "transparent"; }}
                >
                  <Icon name={s.icon} size={14} color={active ? theme.accent : theme.textMuted}/>
                  <span style={{ flex:1 }}>{s.label}</span>
                  {s.count != null && (
                    <span style={{ fontSize:11.5, color: active ? theme.accent : theme.textMuted, fontWeight:500, fontFeatureSettings:'"tnum"' }}>{s.count}</span>
                  )}
                </button>
              );
            })}
          </div>

          <div style={{ marginTop:18, padding:"14px 12px", border:`1px dashed ${theme.cardBorder}`, borderRadius:8, fontSize:12, color:theme.textMuted, lineHeight:1.5 }}>
            <div style={{ fontWeight:600, color:theme.text, marginBottom:4, fontSize:12.5 }}>{t.profile_publish_one}</div>
            <button onClick={onPublish} style={{ marginTop:6, fontSize:12, color:theme.accent, background:"none", border:"none", padding:0, cursor:"pointer", fontWeight:600, fontFamily:"inherit" }}>
              {t.profile_publish_one} →
            </button>
          </div>
        </div>

        {/* Content panel */}
        <div style={{ flex:1, minWidth:0 }}>
          {section === "installed" && (
            <ProfileInstalled exts={installedExts} t={t} lang={lang} theme={theme} cardRadius={cardRadius} onOpenExt={onOpenExt} onUninstall={onUninstall} onBrowse={onBrowse}/>
          )}
          {section === "published" && (
            <ProfilePublished exts={publishedExts} t={t} lang={lang} theme={theme} cardRadius={cardRadius} totalInstalls={totalInstalls} avgRating={avgRating} onOpenExt={onOpenExt} onPublish={onPublish}/>
          )}
          {section === "drafts" && (
            <ProfileDrafts drafts={MY_DRAFTS} t={t} lang={lang} theme={theme} cardRadius={cardRadius} onPublish={onPublish}/>
          )}
          {section === "saved" && (
            <ProfileSaved exts={savedExts} t={t} lang={lang} theme={theme} cardRadius={cardRadius} onOpenExt={onOpenExt} toggleSave={toggleSave} onBrowse={onBrowse}/>
          )}
          {section === "activity" && (
            <ProfileActivity events={RECENT_ACTIVITY} t={t} lang={lang} theme={theme} cardRadius={cardRadius} onOpenExt={onOpenExt}/>
          )}
          {section === "settings" && (
            <ProfileSettings t={t} lang={lang} theme={theme} cardRadius={cardRadius} settingsTab={settingsTab} setSettingsTab={setSettingsTab}/>
          )}
        </div>
      </div>
    </div>
  );
}

function ProfileStat({ value, label, theme, suffix }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-start" }}>
      <div style={{ fontFamily:"'Source Serif 4','Source Serif Pro',Georgia,serif", fontSize:24, fontWeight:600, color:theme.text, lineHeight:1, letterSpacing:"-0.01em", fontFeatureSettings:'"tnum"' }}>
        {value}{suffix && <span style={{ color:theme.accent, marginLeft:2 }}>{suffix}</span>}
      </div>
      <div style={{ fontSize:11.5, color:theme.textMuted, marginTop:5, textTransform:"uppercase", letterSpacing:"0.06em", fontWeight:500 }}>{label}</div>
    </div>
  );
}

function ProfileSectionHeader({ title, theme, action }) {
  return (
    <div style={{ display:"flex", alignItems:"baseline", justifyContent:"space-between", marginBottom:16, paddingBottom:12, borderBottom:`1px solid ${theme.cardBorder}` }}>
