44	// Build a select chain whose `.where()` is BOTH thenable (for the simple
45	// `select(...).from(t).where(...)` shape) AND continues into `.orderBy`/
46	// `.limit` (for the joined-row shape). This lets the same mock cover
47	// both query patterns getDraft uses.
48	function selectChain(rows: unknown[]) {
49	  const limit = vi.fn().mockResolvedValue(rows);
50	  const orderBy = vi.fn().mockReturnValue({ limit });
51	  const whereResult: {
52	    limit: typeof limit;
53	    orderBy: typeof orderBy;
54	    then: Promise<unknown[]>["then"];
55	  } = {
56	    limit,
57	    orderBy,
58	    then: ((onFulfilled, onRejected) =>
59	      Promise.resolve(rows).then(
60	        onFulfilled,
61	        onRejected,
62	      )) as Promise<unknown[]>["then"],
63	  };
64	  const where = vi.fn().mockReturnValue(whereResult);
65	  const leftJoin = vi.fn().mockReturnValue({ where });
66	  const from = vi.fn().mockReturnValue({ where, leftJoin });
67	  return { from, leftJoin, where, orderBy, limit };
68	}
69	
70	function deleteChain() {
71	  const where = vi.fn().mockResolvedValue(undefined);
72	  return { where };
73	}
