function SettingsBody({
  activeTab,
  user,
}: {
  activeTab: SettingsTab;
  user: {
    name: string | null;
    email: string;
    bio: string | null;
    defaultDeptId: string | null;
    joinedLabel: string;
  };
}) {
  // Tab strip + body. The tab strip itself is small enough to inline; if a
  // second section needs tabs we'll extract a shared <TabStrip/>.
  return (
    <div>
      <div className="border-border mb-5 flex gap-1 border-b">
        {SETTINGS_TABS.map((tab) => (
          <SettingsTabLink key={tab} tab={tab} active={tab === activeTab} />
        ))}
      </div>
      {activeTab === "profile" ? <ProfileSettingsForm user={user} /> : null}
    </div>
  );
}

function SettingsTabLink({
  tab,
  active,
}: {
  tab: SettingsTab;
  active: boolean;
}) {
  // Sub-tabs are URL-driven (?tab=...) so they're shareable and the
  // back button works.
  const { Link } = require("@/lib/i18n/navigation") as typeof import("@/lib/i18n/navigation");
  const t = require("next-intl/server") as typeof import("next-intl/server");
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return <SettingsTabLinkClient tab={tab} active={active} />;
}

// Client-rendered sliver so we can use useTranslations for the tab labels.
// (Server-side we'd need getTranslations + await, which complicates the
// signature here — the labels are tiny, so a client component is fine.)
function SettingsTabLinkClient({
  tab,
  active,
}: {
  tab: SettingsTab;
  active: boolean;
}) {
  return <SettingsTabLinkInner tab={tab} active={active} />;
}

import { SettingsTabLinkInner } from "@/components/profile/settings-tab-link";

