): Promise<boolean> {
  const row = await db
    .select({ collectionId: collectionItems.collectionId })
    .from(collectionItems)
    .where(
      and(
        eq(collectionItems.collectionId, collectionId),
        eq(collectionItems.extensionId, extensionId),
      ),
    )
    .limit(1);
  return row.length > 0;
}

