import { and, desc, eq, isNull, sql } from "drizzle-orm";

import { db } from "@/lib/db/client";
import { collectionItems, collections } from "@/lib/db/schema/collection";
import {
  extensionVersions,
  extensions,
} from "@/lib/db/schema/extension";
import { installs, ratings } from "@/lib/db/schema/activity";

// Minimal row shape rendered by the profile's Installed list.
export type ProfileInstalledRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  installedVersion: string;
  installedAt: Date;
};

export async function getInstalledForUser(
  userId: string,
): Promise<ProfileInstalledRow[]> {
  // Active installs only — `uninstalledAt IS NULL`. Join `extensions` so we
  // can render the name + slug + icon without a second round-trip. Ordering
  // by `installedAt DESC` matches "most recently installed first".
  const rows = await db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      installedVersion: installs.version,
      installedAt: installs.installedAt,
    })
    .from(installs)
    .innerJoin(extensions, eq(extensions.id, installs.extensionId))
    .where(and(eq(installs.userId, userId), isNull(installs.uninstalledAt)))
    .orderBy(desc(installs.installedAt));
  return rows;
}

export type ProfilePublishedRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  latestVersion: string | null;
  downloadsCount: number;
  starsAvg: string;
  ratingsCount: number;
};

export async function getPublishedForUser(
  userId: string,
): Promise<ProfilePublishedRow[]> {
  // We want the latest published version per extension — DISTINCT ON keeps
  // the query single-pass. Drizzle doesn't have a first-class DISTINCT ON,
  // so we collapse client-side after ORDER BY (mirrors getMyExtensions).
  const rows = await db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      latestVersion: extensionVersions.version,
      downloadsCount: extensions.downloadsCount,
      starsAvg: extensions.starsAvg,
      ratingsCount: extensions.ratingsCount,
    })
    .from(extensions)
    .leftJoin(
      extensionVersions,
      and(
        eq(extensionVersions.extensionId, extensions.id),
        eq(extensionVersions.status, "ready"),
      ),
    )
    .where(
      and(
        eq(extensions.publisherUserId, userId),
        eq(extensions.visibility, "published"),
      ),
    )
    .orderBy(
      desc(extensions.publishedAt),
      desc(extensionVersions.publishedAt),
    );

  const seen = new Set<string>();
  const out: ProfilePublishedRow[] = [];
  for (const r of rows) {
    if (seen.has(r.extensionId)) continue;
    seen.add(r.extensionId);
    out.push(r);
  }
  return out;
}

export type ProfileDraftRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  updatedAt: Date;
  latestStatus: string | null;
};

export async function getDraftsForUser(
  userId: string,
): Promise<ProfileDraftRow[]> {
  // "Draft" = extension.visibility == "draft". Latest version's status
  // surfaces why a draft is stuck (e.g. "scanning", "rejected") so the row
  // can mirror the publish dashboard's status pill.
  const rows = await db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      updatedAt: extensions.updatedAt,
      latestStatus: extensionVersions.status,
    })
    .from(extensions)
    .leftJoin(
      extensionVersions,
      eq(extensionVersions.extensionId, extensions.id),
    )
    .where(
      and(
        eq(extensions.publisherUserId, userId),
        eq(extensions.visibility, "draft"),
      ),
    )
    .orderBy(
      desc(extensions.updatedAt),
      desc(extensionVersions.createdAt),
    );

  const seen = new Set<string>();
  const out: ProfileDraftRow[] = [];
  for (const r of rows) {
    if (seen.has(r.extensionId)) continue;
    seen.add(r.extensionId);
    out.push(r);
  }
  return out;
}

export type ProfileSavedRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  savedAt: Date;
};

export async function getSavedForUser(
  userId: string,
): Promise<ProfileSavedRow[]> {
  // The system "saved" collection is per-user. We join through
  // collection_items rather than reading the collection id first because
  // a single JOIN is cheaper than two round-trips, and a user without a
  // saved collection simply returns no rows.
  return db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      savedAt: collectionItems.addedAt,
    })
    .from(collectionItems)
    .innerJoin(
      collections,
      and(
        eq(collections.id, collectionItems.collectionId),
        eq(collections.ownerUserId, userId),
        eq(collections.systemKind, "saved"),
      ),
    )
    .innerJoin(extensions, eq(extensions.id, collectionItems.extensionId))
    .orderBy(desc(collectionItems.addedAt));
}

export type ProfileStats = {
  installedCount: number;
  publishedCount: number;
  totalInstallsOfMine: number;
  avgRatingOfMine: number | null;
};

export async function getProfileStats(userId: string): Promise<ProfileStats> {
  // Three small aggregates, one query each — clearer than a single CTE and
  // each one is cheap (covered by existing indexes).
  const installedCountRow = await db
    .select({ c: sql<number>`count(*)::int` })
    .from(installs)
    .where(and(eq(installs.userId, userId), isNull(installs.uninstalledAt)));

  const pubAgg = await db
    .select({
      count: sql<number>`count(*)::int`,
      totalInstalls: sql<number>`coalesce(sum(${extensions.downloadsCount}),0)::int`,
      // Weighted average so an extension with 100 ratings counts 100× more
      // than one with a single rating. Returns null when no rated extensions
      // exist; the UI shows "—" for that case.
      weightedStars: sql<
        string | null
      >`case when sum(${extensions.ratingsCount}) = 0 then null else sum(${extensions.starsAvg}::numeric * ${extensions.ratingsCount})::numeric / sum(${extensions.ratingsCount}) end`,
    })
    .from(extensions)
    .where(
      and(
        eq(extensions.publisherUserId, userId),
        eq(extensions.visibility, "published"),
      ),
    );

  const pub = pubAgg[0] ?? {
    count: 0,
    totalInstalls: 0,
    weightedStars: null,
  };
  return {
    installedCount: installedCountRow[0]?.c ?? 0,
    publishedCount: pub.count,
    totalInstallsOfMine: pub.totalInstalls,
    avgRatingOfMine:
      pub.weightedStars != null ? Number(pub.weightedStars) : null,
  };
}

export type ProfileActivityEvent =
  | {
      kind: "installed";
      at: Date;
      extensionId: string;
      slug: string;
      name: string;
      version: string;
    }
  | {
      kind: "published";
      at: Date;
      extensionId: string;
      slug: string;
      name: string;
      version: string;
    }
  | {
      kind: "rated";
      at: Date;
      extensionId: string;
      slug: string;
      name: string;
      stars: number;
    };

const ACTIVITY_LIMIT = 20;

export async function getActivityForUser(
  userId: string,
): Promise<ProfileActivityEvent[]> {
  // Activity is a union of three event sources — there's no dedicated event
  // log table yet. Each source is cheap (indexed by userId or
  // publisherUserId), so we pull the most-recent N from each and merge in
  // memory rather than building a heavyweight UNION ALL query with views.
  const [installRows, pubRows, ratingRows] = await Promise.all([
    db
      .select({
        at: installs.installedAt,
        extensionId: extensions.id,
        slug: extensions.slug,
        name: extensions.name,
        version: installs.version,
      })
      .from(installs)
      .innerJoin(extensions, eq(extensions.id, installs.extensionId))
      .where(eq(installs.userId, userId))
      .orderBy(desc(installs.installedAt))
      .limit(ACTIVITY_LIMIT),
    db
      .select({
        at: extensionVersions.publishedAt,
        extensionId: extensions.id,
        slug: extensions.slug,
        name: extensions.name,
        version: extensionVersions.version,
      })
      .from(extensionVersions)
      .innerJoin(extensions, eq(extensions.id, extensionVersions.extensionId))
      .where(
        and(
          eq(extensions.publisherUserId, userId),
          eq(extensionVersions.status, "ready"),
        ),
      )
      .orderBy(desc(extensionVersions.publishedAt))
      .limit(ACTIVITY_LIMIT),
    db
      .select({
        at: ratings.createdAt,
        extensionId: extensions.id,
        slug: extensions.slug,
        name: extensions.name,
        stars: ratings.stars,
      })
      .from(ratings)
      .innerJoin(extensions, eq(extensions.id, ratings.extensionId))
      .where(eq(ratings.userId, userId))
      .orderBy(desc(ratings.createdAt))
      .limit(ACTIVITY_LIMIT),
  ]);

  const merged: ProfileActivityEvent[] = [
    ...installRows
      .filter((r) => r.at != null)
      .map(
        (r): ProfileActivityEvent => ({
          kind: "installed",
          at: r.at as Date,
          extensionId: r.extensionId,
          slug: r.slug,
          name: r.name,
          version: r.version,
        }),
      ),
    ...pubRows
      .filter((r) => r.at != null)
      .map(
        (r): ProfileActivityEvent => ({
          kind: "published",
          at: r.at as Date,
          extensionId: r.extensionId,
          slug: r.slug,
          name: r.name,
          version: r.version,
        }),
      ),
    ...ratingRows
      .filter((r) => r.at != null)
      .map(
        (r): ProfileActivityEvent => ({
          kind: "rated",
          at: r.at as Date,
          extensionId: r.extensionId,
          slug: r.slug,
          name: r.name,
          stars: r.stars,
        }),
      ),
  ];

  merged.sort((a, b) => b.at.getTime() - a.at.getTime());
  return merged.slice(0, ACTIVITY_LIMIT);
}

