          href="/extensions"
          className="bg-primary text-primary-foreground hover:opacity-90 mt-1 inline-flex items-center gap-1.5 rounded-md px-4 py-2 text-[13px] font-semibold transition-opacity"
        >
          {t("browse")}
        </Link>
      </div>
    );
  }

