// @vitest-environment happy-dom
import { describe, it, expect, vi, afterEach } from "vitest";
import { render, screen, cleanup } from "@testing-library/react";

import { ProfileHero } from "./profile-hero";

// Echo the translation key so assertions can look for it directly.
vi.mock("next-intl", () => ({
  useTranslations: () => (key: string) => key,
}));

afterEach(cleanup);

describe("ProfileHero", () => {
  const base = {
    name: "Alice Bob",
    email: "alice@example.com",
    joinedLabel: "Joined Apr 2024",
    deptLabel: "Cloud Platform · Engineering",
  };

  it("renders the display name and initials from name", () => {
    render(<ProfileHero {...base} />);
    expect(screen.getByRole("heading", { level: 1 })).toHaveTextContent(
      "Alice Bob",
    );
    // The avatar is decorative — initials are visual only, but we still want
    // them present so the visual matches the design.
    expect(screen.getByText("AB")).toBeInTheDocument();
  });

  it("falls back to first email letter when name is null", () => {
    render(<ProfileHero {...base} name={null} />);
    expect(screen.getByText("A")).toBeInTheDocument();
  });

  // Empty string is a real shape we'll see in the DB (the column is nullable
  // and better-auth sometimes round-trips `""` rather than null) — initials
  // must not crash on it.
  it("falls back to first email letter when name is empty", () => {
    render(<ProfileHero {...base} name="" />);
    expect(screen.getByText("A")).toBeInTheDocument();
  });

  it("collapses consecutive spaces in name before extracting initials", () => {
    render(<ProfileHero {...base} name="Alice  Bob  Carter" />);
    expect(screen.getByText("AB")).toBeInTheDocument();
  });

  it("renders a single initial for a single-token name", () => {
    render(<ProfileHero {...base} name="Q" />);
    // The h1 also renders "Q" when the name is one letter; scope to the
    // avatar div so the assertion isn't ambiguous.
    expect(screen.getByText("Q", { selector: "div" })).toBeInTheDocument();
  });

  it("renders the (static) role label, the resolved dept label, and the joined label", () => {
    render(<ProfileHero {...base} />);
    // Role is a static i18n key — the echo-mock surfaces "role".
    expect(screen.getByText("role")).toBeInTheDocument();
    expect(
      screen.getByText("Cloud Platform · Engineering"),
    ).toBeInTheDocument();
    expect(screen.getByText("Joined Apr 2024")).toBeInTheDocument();
  });

  it("renders the deptUnset placeholder when deptLabel is null", () => {
    render(<ProfileHero {...base} deptLabel={null} />);
    expect(screen.getByText("deptUnset")).toBeInTheDocument();
  });

  it("renders the 4 stats (installed, published, total installs, avg rating)", () => {
    render(
      <ProfileHero
        {...base}
        stats={{
          installedCount: 7,
          publishedCount: 3,
          totalInstallsOfMine: 1234,
          avgRatingOfMine: 4.5,
        }}
      />,
    );
    expect(screen.getByText("7")).toBeInTheDocument();
    expect(screen.getByText("3")).toBeInTheDocument();
    expect(screen.getByText(/1,234/)).toBeInTheDocument();
    // Avg rating renders one-decimal.
    expect(screen.getByText("4.5")).toBeInTheDocument();
    // Stat labels come from i18n.
    expect(screen.getByText("stats.installed")).toBeInTheDocument();
    expect(screen.getByText("stats.published")).toBeInTheDocument();
    expect(screen.getByText("stats.installs")).toBeInTheDocument();
    expect(screen.getByText("stats.rating")).toBeInTheDocument();
  });

  it("renders an em-dash when avgRatingOfMine is null (no rated extensions)", () => {
    render(
      <ProfileHero
        {...base}
        stats={{
          installedCount: 0,
          publishedCount: 0,
          totalInstallsOfMine: 0,
          avgRatingOfMine: null,
        }}
      />,
    );
    expect(screen.getByText("—")).toBeInTheDocument();
  });
});

import { and, desc, eq, isNull } from "drizzle-orm";

import { db } from "@/lib/db/client";
import { installs, ratings } from "@/lib/db/schema/activity";
import { collectionItems, collections } from "@/lib/db/schema/collection";
import {
  extensionVersions,
  extensions,
} from "@/lib/db/schema/extension";

export type ProfileInstalledRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  installedVersion: string;
  installedAt: Date;
};

export type ProfileSavedRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  savedAt: Date;
};

export async function getSavedForUser(
  userId: string,
): Promise<ProfileSavedRow[]> {
  // Join through `collection_items` rather than reading the collection id
  // first — one JOIN is cheaper than two round-trips, and a user without a
  // saved collection simply returns no rows.
  return db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      savedAt: collectionItems.addedAt,
    })
    .from(collectionItems)
    .innerJoin(
      collections,
      and(
        eq(collections.id, collectionItems.collectionId),
        eq(collections.ownerUserId, userId),
        eq(collections.systemKind, "saved"),
      ),
    )
    .innerJoin(extensions, eq(extensions.id, collectionItems.extensionId))
    .orderBy(desc(collectionItems.addedAt));
}

export type ProfileDraftRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  updatedAt: Date;
  latestStatus: string | null;
};

export async function getDraftsForUser(
  userId: string,
): Promise<ProfileDraftRow[]> {
  // "Draft" = extension.visibility == "draft". Latest version's status
  // surfaces why a draft is stuck (e.g. "scanning", "rejected") so the
  // row can mirror the publish dashboard's status pill.
  const rows = await db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      updatedAt: extensions.updatedAt,
      latestStatus: extensionVersions.status,
    })
    .from(extensions)
    .leftJoin(
      extensionVersions,
      eq(extensionVersions.extensionId, extensions.id),
    )
    .where(
      and(
        eq(extensions.publisherUserId, userId),
        eq(extensions.visibility, "draft"),
      ),
    )
    .orderBy(
      desc(extensions.updatedAt),
      desc(extensionVersions.createdAt),
    );

  const seen = new Set<string>();
  const out: ProfileDraftRow[] = [];
  for (const r of rows) {
    if (seen.has(r.extensionId)) continue;
    seen.add(r.extensionId);
    out.push(r);
  }
  return out;
}

export async function getInstalledForUser(
  userId: string,
): Promise<ProfileInstalledRow[]> {
  // Active installs only — `uninstalledAt IS NULL`. Order by `installedAt
  // DESC` matches the design's "most recently installed first" sort.
  return db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      installedVersion: installs.version,
      installedAt: installs.installedAt,
    })
    .from(installs)
    .innerJoin(extensions, eq(extensions.id, installs.extensionId))
    .where(and(eq(installs.userId, userId), isNull(installs.uninstalledAt)))
    .orderBy(desc(installs.installedAt));
}

export type ProfilePublishedRow = {
  extensionId: string;
  slug: string;
  name: string;
  category: string;
  iconColor: string | null;
  latestVersion: string | null;
  downloadsCount: number;
  starsAvg: string;
  ratingsCount: number;
};

export async function getPublishedForUser(
  userId: string,
): Promise<ProfilePublishedRow[]> {
  // Latest published version per extension. Drizzle doesn't expose
  // DISTINCT ON cleanly, so we ORDER BY publishedAt desc and collapse
  // duplicates client-side — mirrors `getMyExtensions` in
  // lib/actions/publish.ts.
  const rows = await db
    .select({
      extensionId: extensions.id,
      slug: extensions.slug,
      name: extensions.name,
      category: extensions.category,
      iconColor: extensions.iconColor,
      latestVersion: extensionVersions.version,
      downloadsCount: extensions.downloadsCount,
      starsAvg: extensions.starsAvg,
      ratingsCount: extensions.ratingsCount,
    })
    .from(extensions)
    .leftJoin(
      extensionVersions,
      and(
        eq(extensionVersions.extensionId, extensions.id),
        eq(extensionVersions.status, "ready"),
      ),
    )
    .where(
      and(
        eq(extensions.publisherUserId, userId),
        eq(extensions.visibility, "published"),
      ),
    )
    .orderBy(
      desc(extensions.publishedAt),
      desc(extensionVersions.publishedAt),
    );

  const seen = new Set<string>();
  const out: ProfilePublishedRow[] = [];
  for (const r of rows) {
    if (seen.has(r.extensionId)) continue;
    seen.add(r.extensionId);
    out.push(r);
  }
  return out;
}

export type ProfileActivityEvent =
  | {
      kind: "installed";
      at: Date;
      extensionId: string;
      slug: string;
      name: string;
      version: string;
    }
  | {
      kind: "published";
      at: Date;
      extensionId: string;
      slug: string;
      name: string;
      version: string;
    }
  | {
      kind: "rated";
      at: Date;
      extensionId: string;
      slug: string;
      name: string;
      stars: number;
    };

const ACTIVITY_LIMIT = 20;

export async function getActivityForUser(
  userId: string,
): Promise<ProfileActivityEvent[]> {
  // No dedicated activity_log table yet. Activity is a union of three event
  // sources (installs, my published versions, my ratings). Each source is
  // indexed by user — pull the most-recent N from each and merge in memory
  // rather than a heavyweight UNION ALL.
  const [installRows, pubRows, ratingRows] = await Promise.all([
    db
      .select({
        at: installs.installedAt,
        extensionId: extensions.id,
        slug: extensions.slug,
        name: extensions.name,
        version: installs.version,
      })
      .from(installs)
      .innerJoin(extensions, eq(extensions.id, installs.extensionId))
      .where(eq(installs.userId, userId))
      .orderBy(desc(installs.installedAt))
      .limit(ACTIVITY_LIMIT),
    db
      .select({
        at: extensionVersions.publishedAt,
        extensionId: extensions.id,
        slug: extensions.slug,
        name: extensions.name,
        version: extensionVersions.version,
      })
      .from(extensionVersions)
      .innerJoin(
        extensions,
        eq(extensions.id, extensionVersions.extensionId),
      )
      .where(
        and(
          eq(extensions.publisherUserId, userId),
          eq(extensionVersions.status, "ready"),
        ),
      )
      .orderBy(desc(extensionVersions.publishedAt))
      .limit(ACTIVITY_LIMIT),
    db
      .select({
        at: ratings.createdAt,
        extensionId: extensions.id,
        slug: extensions.slug,
        name: extensions.name,
        stars: ratings.stars,
      })
      .from(ratings)
      .innerJoin(extensions, eq(extensions.id, ratings.extensionId))
      .where(eq(ratings.userId, userId))
      .orderBy(desc(ratings.createdAt))
      .limit(ACTIVITY_LIMIT),
  ]);

  const merged: ProfileActivityEvent[] = [
    ...installRows
      .filter((r) => r.at != null)
      .map(
        (r): ProfileActivityEvent => ({
          kind: "installed",
          at: r.at as Date,
          extensionId: r.extensionId,
          slug: r.slug,
          name: r.name,
          version: r.version,
        }),
      ),
    ...pubRows
      .filter((r) => r.at != null)
      .map(
        (r): ProfileActivityEvent => ({
          kind: "published",
          at: r.at as Date,
          extensionId: r.extensionId,
          slug: r.slug,
          name: r.name,
          version: r.version,
        }),
      ),
    ...ratingRows
      .filter((r) => r.at != null)
      .map(
        (r): ProfileActivityEvent => ({
          kind: "rated",
          at: r.at as Date,
          extensionId: r.extensionId,
          slug: r.slug,
          name: r.name,
          stars: r.stars,
        }),
      ),
  ];

  merged.sort((a, b) => b.at.getTime() - a.at.getTime());
  return merged.slice(0, ACTIVITY_LIMIT);
}

